$pdf->SetDrawColor(0);
$pdf->SetXY(10,10);

$tp = 05;
$ap = $pdf->anchoPagina - 2;
$mp = ($ap / 2);
$lp = $pdf->largoPagina;

// Frame Principal
$pdf->Rect(005, 005, $ap, $lp, 0.1);

// Nombre Empresa
$pdf->Rect(005, 005, $mp, 045, 0.1);

$datapath = $_SESSION['datapath'];
$file = "../database/$datapath/img/logo1.jpg"; 

if (is_file($file))
{
	$posx = 20;
	$posy = 7;
	$width = 65;
	$pdf->Image($file, $posx + $this->offsetX, $posy + $this->offsetY, $width);
}

// Datos Comprobante
$pdf->Rect($mp + 5, 005, $mp, 045, 0.1);

/// letra
$pdf->setFillColor(255,255,255);
$pdf->Rect($mp - 2 , 005, 015, 015, 'F');
$pdf->Rect($mp - 2 , 005, 015, 015, 0.1);

// Cliente
$pdf->Rect(005, 055, $ap, 045, 0.1);

// DATOS EMPRESA
$pdf->SetFontSize(8);
$pdf->text(010, 035, $_SESSION['properties']['nombre']);
$pdf->text(010, 041, $_SESSION['properties']['localidad1'].': '.$_SESSION['properties']['direccion1'].' - Tel.: '.$_SESSION['properties']['telefono1'].' (C.P. '.$_SESSION['properties']['cp1'].')');				

$pdf->text(010, 045, $_SESSION['properties']['localidad2'].': '.$_SESSION['properties']['direccion2'].' - Tel.: '.$_SESSION['properties']['telefono2'].' (C.P. '.$_SESSION['properties']['cp2'].')');

$pdf->text(010, 051, 'e-mail: '.$_SESSION['properties']['email'].' | '.$_SESSION['properties']['web']);

